package main

import (
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

func fileHandler(uploadDir string) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		filename := strings.TrimPrefix(r.URL.Path, "/files/")
		if filename == "" || filename == "." || filename == "/" {
			http.Error(w, "missing filename", http.StatusBadRequest)
			return
		}

		cleanName := filepath.Clean(filename)
		if cleanName == "." || strings.HasPrefix(cleanName, "..") || filepath.IsAbs(cleanName) {
			http.Error(w, "invalid filename", http.StatusBadRequest)
			return
		}

		fullPath := filepath.Join(uploadDir, cleanName)
		absUploadDir, err := filepath.Abs(uploadDir)
		if err != nil {
			http.Error(w, "server error", http.StatusInternalServerError)
			return
		}
		absFilePath, err := filepath.Abs(fullPath)
		if err != nil {
			http.Error(w, "server error", http.StatusInternalServerError)
			return
		}
		if absFilePath != absUploadDir && !strings.HasPrefix(absFilePath, absUploadDir+string(os.PathSeparator)) {
			http.Error(w, "invalid filename", http.StatusBadRequest)
			return
		}

		file, err := os.Open(absFilePath)
		if err != nil {
			if os.IsNotExist(err) {
				http.NotFound(w, r)
				return
			}
			http.Error(w, "could not open file", http.StatusInternalServerError)
			return
		}
		defer file.Close()

		info, err := file.Stat()
		if err != nil {
			http.Error(w, "could not stat file", http.StatusInternalServerError)
			return
		}
		if info.IsDir() {
			http.Error(w, "not a file", http.StatusBadRequest)
			return
		}

		http.ServeContent(w, r, info.Name(), info.ModTime(), file)
	}
}

func main() {
	uploadDir := "./uploads"

	http.HandleFunc("/files/", fileHandler(uploadDir))

	log.Println("listening on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}